// @fontsource-variable/* ships CSS only (no type declarations). These are
// imported purely for their side effect (injecting @font-face rules), so a
// bare ambient module declaration satisfies TypeScript 6's stricter
// side-effect-import check (TS2882) without inventing a fake API surface.
declare module "@fontsource-variable/inter";
declare module "@fontsource-variable/source-serif-4";
